sections.body:
A practical approach is a centralized theme file that stores editable tokens. Example:

{
  "colors": {
    "primary": "#1e90ff",
    "secondary": "#ff6347",
    "background": "#ffffff",
    "text": "#000000"
  },
  "spacing": {
    "small": "8px",
    "medium": "16px",
    "large": "32px"
  },
  "typography": {
    "fontFamily": "Arial, sans-serif",
    "headingSize": "2rem",
    "bodySize": "1rem"
  },
  "buttons": {
    "variant": "rounded"
  }
}

Store this file in your content backend and treat it as a source of truth for global theme values.

Then expose those keys in Tina so editors can update them visually. Example form setup:

import { useCMS, useForm, usePlugin } from "tinacms"
import themeData from "./theme.json"

const formConfig = {
  id: "global-theme",
  label: "Global Theme",
  initialValues: themeData,
  fields: [
    { name: "colors.primary", label: "Primary Color", component: "color" },
    { name: "colors.secondary", label: "Secondary Color", component: "color" },
    { name: "spacing.medium", label: "Medium Spacing", component: "text" },
    { name: "typography.fontFamily", label: "Font Family", component: "text" },
    {
      name: "buttons.variant",
      label: "Button Style",
      component: "select",
      options: ["rounded", "square"]
    }
  ],
  onSubmit: (values) => {
    // persist theme values to your source of truth
  }
}

const [themeForm] = useForm(formConfig)
usePlugin(themeForm)

Theme edits become global only when components read from that shared config. Example:

import theme from "./theme.json"

export function Button({ children }) {
  return (
    <button
      style={{
        backgroundColor: theme.colors.primary,
        color: theme.colors.text,
        padding: theme.spacing.medium,
        borderRadius: theme.buttons.variant === "rounded" ? "9999px" : "4px",
        fontFamily: theme.typography.fontFamily
      }}
    >
      {children}
    </button>
  )
}

You can apply the same pattern to layout variants (for example grid vs list) and a ThemeProvider for optional live preview while editing.
